import{_ as e,o as r,c as t,a2 as l}from"./chunks/framework.ZhLefgN8.js";const f=JSON.parse('{"title":"主子账户资金划转","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"transfers-and-fx/master-sub-transfer.md","filePath":"zh-CN/transfers-and-fx/master-sub-transfer.md"}'),i={name:"transfers-and-fx/master-sub-transfer.md"};function s(n,a,o,d,h,u){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="主子账户资金划转" tabindex="-1">主子账户资金划转 <a class="header-anchor" href="#主子账户资金划转" aria-label="Permalink to &quot;主子账户资金划转&quot;">​</a></h1><p>资金划转（Fund Transfer）是将资金从一个账户转移到另一个账户的操作，可以避免来回出入金，提高效率。</p><p>主子账户资金划转适用于同时拥有长桥香港综合账户和日内融账户的用户，可在主账户（综合账户）与子账户（日内融账户）之间进行资金划拨。</p><h2 id="支持币种" tabindex="-1">支持币种 <a class="header-anchor" href="#支持币种" aria-label="Permalink to &quot;支持币种&quot;">​</a></h2><p>港元（HKD）、美元（USD）</p><h2 id="到账时间" tabindex="-1">到账时间 <a class="header-anchor" href="#到账时间" aria-label="Permalink to &quot;到账时间&quot;">​</a></h2><p>预计实时到账</p><h2 id="手续费" tabindex="-1">手续费 <a class="header-anchor" href="#手续费" aria-label="Permalink to &quot;手续费&quot;">​</a></h2><p>免费</p><h2 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h2><p>长桥 App - 资产 - 全部功能 - 资金划转 - 主子账户资金划转，选择转入/转出账户，输入金额后提交。</p><h2 id="划转限额" tabindex="-1">划转限额 <a class="header-anchor" href="#划转限额" aria-label="Permalink to &quot;划转限额&quot;">​</a></h2><ul><li>单日转账总融资划转金额：不超过 50 万 HKD</li><li>单笔转账融资划转金额：不超过 10 万 HKD</li><li>单日转账次数：不超过 10 次</li></ul><h2 id="开通条件与新加坡账户限制" tabindex="-1">开通条件与新加坡账户限制 <a class="header-anchor" href="#开通条件与新加坡账户限制" aria-label="Permalink to &quot;开通条件与新加坡账户限制&quot;">​</a></h2><ul><li>需先开通长桥香港综合账户，才能开通日内融账户</li><li>目前长桥新加坡暂不支持主子账户资金划转</li><li>如账户资金在余额通中，资金划转额度会显示为 0，需先赎回余额通或等待资金交收完毕</li></ul>',15)])])}const p=e(i,[["render",s]]);export{f as __pageData,p as default};
